        if (strlen($alias) > 64) {
            throw new RuntimeException('File aliases must be 64 characters or fewer.');
        }
        if (!file_alias_valid($alias)) {
            throw new RuntimeException("Invalid file alias: {$alias}");
        }
        $out[] = $alias;
    }
    return array_values(array_unique($out));
}
