        }
    }
    $extraKeys = array_values(array_filter(array_keys($data), static fn(string $key): bool=>!in_array($key, $sections, true)));
    foreach ($extraKeys as $key) {
        $body .= "\n" . var_export($key, true) . ' => ' . export_php_value($data[$key]) . ",\n";
    }
