    }
    $pos = max(0, min($before, $size));
    $carry = '';
    $lines = [];
    $skipTrailingEmpty = true;
    while ($pos > 0 && count($lines) <= $limit) {
        $read = min(8192, $pos);
        $pos -= $read;
        fseek($fh, $pos);
        $chunk = (string)fread($fh, $read);
        $data = $chunk . $carry;
        $parts = explode("\n", $data);
