            if ($skipTrailingEmpty && $complete[$i]['text'] === '' && $i === count($complete) - 1) {
                $skipTrailingEmpty = false;
                continue;
            }
            $skipTrailingEmpty = false;
            $lines[] = $complete[$i];
            if (count($lines) > $limit) {
                break 2;
            }
        }
