    }
    $realDir = rtrim($realDir, DIRECTORY_SEPARATOR) . DIRECTORY_SEPARATOR;
    $pathDir = rtrim($pathDir, DIRECTORY_SEPARATOR) . DIRECTORY_SEPARATOR;
    return str_starts_with($pathDir, $realDir);
