function missing_file_aliases(array $cfg, array $data): array
{
    $base = rtrim((string)($cfg['download_base_dir'] ?? ''), '/');
    if ($base === '' || !is_dir($base)) {
        return array_keys((array)($data['files'] ?? []));
    }
    $missing = [];
    foreach ((array)($data['files'] ?? []) as $alias => $relPath) {
        $path = $base . '/' . ltrim((string)$relPath, '/');
        if (!is_file($path) || !is_readable($path)) {
            $missing[] = (string)$alias;
        }
    }
    return $missing;
}
function discovered_download_files(string $downloadBaseDir): array
{
    $base = realpath(rtrim($downloadBaseDir, '/'));
    if ($base === false || !is_dir($base) || !is_readable($base)) {
        return [];
    }
    $base = rtrim($base, DIRECTORY_SEPARATOR);
    $files = [];
    try {
        $iterator = new RecursiveIteratorIterator(
            new RecursiveDirectoryIterator($base, FilesystemIterator::SKIP_DOTS),
            RecursiveIteratorIterator::LEAVES_ONLY
        );
        foreach ($iterator as $item) {
            if (!$item instanceof SplFileInfo || !$item->isFile() || $item->isLink()) {
                continue;
            }
            $real = $item->getRealPath();
            if (!is_string($real) || !str_starts_with($real, $base . DIRECTORY_SEPARATOR)) {
                continue;
            }
            $relative = str_replace(DIRECTORY_SEPARATOR, '/', substr($real, strlen($base) + 1));
            if (is_executable($real) || !rel_path_valid($relative) || relative_path_has_hidden_segment($relative) || !downloadable_file_name_safe($relative)) {
                continue;
            }
            $files[$relative] = $relative;
        }
    } catch (Throwable) {
        return [];
    }
    ksort($files, SORT_NATURAL | SORT_FLAG_CASE);
    return array_values($files);
}
function with_totman_lock(array $cfg, callable $callback): mixed
{
    $stateDir = rtrim((string)($cfg['state_dir'] ?? ''), '/');
    $lockFile = $stateDir . '/' . basename((string)($cfg['lock_file'] ?? 'totman.lock'));
    $lock = fopen($lockFile, 'c+');
    if ($lock === false) {
        throw new RuntimeException("Could not open lock file: {$lockFile}");
    }
    try {
        if (!flock($lock, LOCK_EX)) {
            throw new RuntimeException('Could not acquire state lock.');
        }
        return $callback();
    } finally {
        flock($lock, LOCK_UN);
        fclose($lock);
    }
}
