function file_rows_for_view(array $configuredFiles, string $downloadBaseDir): array
{
    $discovered = array_fill_keys(discovered_download_files($downloadBaseDir), true);
    $rows = [];
    foreach ($configuredFiles as $alias => $path) {
        $alias = (string)$alias;
        $path = (string)$path;
        $exists = isset($discovered[$path]);
        $rows[] = [$alias,$path,$alias,$path,true,$exists,$exists ? 'configured_found' : 'configured_missing'];
        unset($discovered[$path]);
    }
    foreach (array_keys($discovered) as $path) {
        $rows[] = ['',(string)$path,'',(string)$path,false,true,'discovered'];
    }
    return $rows;
}
function render_recipients(array $recips, array $flash, string $downloadBaseDir = '/var/lib/totman/files'): void
{
    $data = $recips['data'];
    $postback = take_postback('recipients');
    $messageRows = [];
    $fileRows = [];
    $recipientRows = [];
    if ($postback !== []) {
        foreach ((array)($postback['message_key'] ?? []) as $i => $key) {
            $messageRows[] = [(string)$key,['subject' => (string)(($postback['message_subject'] ?? [])[$i] ?? ''),'body' => (string)(($postback['message_body'] ?? [])[$i] ?? ''),'single_use_notice' => (string)(($postback['message_single_use_notice'] ?? [])[$i] ?? ''),],];
        }
        foreach ((array)($postback['file_alias'] ?? []) as $i => $alias) {
            $originalAlias = (string)(($postback['file_original_alias'] ?? [])[$i] ?? '');
            $originalPath = (string)(($postback['file_original_path'] ?? [])[$i] ?? '');
            $path = (string)(($postback['file_path'] ?? [])[$i] ?? '');
            $exists = in_array($path, discovered_download_files($downloadBaseDir), true);
            $fileRows[] = [(string)$alias,$path,$originalAlias,$originalPath,$originalAlias !== '',$exists,$originalAlias !== '' && !$exists ? 'configured_missing' : ($originalAlias !== '' ? 'configured_found' : 'discovered')];
        }
        foreach ((array)($postback['recipient_name'] ?? []) as $i => $name) {
            $recipientRows[] = [(string)$name,(string)(($postback['recipient_address'] ?? [])[$i] ?? ''),(string)(($postback['recipient_message_key'] ?? [])[$i] ?? ''),postback_alias_list($postback, 'recipient_normal_files', (int)$i),postback_alias_list($postback, 'recipient_single_files', (int)$i),];
        }
    } else {
        foreach ((array)($data['messages'] ?? []) as $key => $message) {
            $messageRows[] = [(string)$key,(array)$message];
        }
        $fileRows = file_rows_for_view((array)($data['files'] ?? []), $downloadBaseDir);
        $recipientRows = array_map(static fn($row): array=>(array)$row, (array)($data['recipients'] ?? []));
    }
    $messageKeys = array_values(array_unique(array_filter(array_map(static fn(array $row): string=>(string)$row[0], $messageRows), static fn(string $value): bool=>$value !== '')));
    $fileAliases = array_values(array_unique(array_filter(array_map(static fn(array $row): string=>(string)$row[0], $fileRows), static fn(string $value): bool=>$value !== '')));
    echo'<section id="view-recipients" class="hidden view-animate" role="tabpanel" aria-labelledby="tab-recipients"><form method="post">' . csrf_field() . '<input type="hidden" name="action" value="save_recipients"><input type="hidden" name="recipients_fingerprint" value="' . h($recips['fingerprint']) . '"><div class="sub-nav" role="tablist" aria-label="' . h(t('Recipients sections')) . '"><button type="button" id="tab-recipients-list" class="sub-nav-item active" data-sub="recipients-list" role="tab" aria-selected="true" aria-controls="recipients-list">' . h(t('List')) . '</button><button type="button" id="tab-recipients-messages" class="sub-nav-item" data-sub="recipients-messages" role="tab" aria-selected="false" aria-controls="recipients-messages">' . h(t('Messages')) . '</button><button type="button" id="tab-recipients-files" class="sub-nav-item" data-sub="recipients-files" role="tab" aria-selected="false" aria-controls="recipients-files">' . h(t('Files')) . '</button></div>';
    render_flash($flash, 'recipients');
    echo'<div id="recipients-list" class="sub-view" role="tabpanel"><div class="action-bar"><button type="button" class="btn-primary add-row" data-template="recipient-template" data-target="recipient-cards" data-insert="prepend" data-focus="input[name=&quot;recipient_name[]&quot;]">' . h(t('Add Recipient')) . '</button></div><div id="recipient-cards">';
    $recipientIndex = 0;
    foreach ($recipientRows as $row) {
        recipient_row((array)$row, $messageKeys, $fileAliases, $recipientIndex++);
    }
    echo'</div></div><div id="recipients-messages" class="sub-view hidden" role="tabpanel"><div class="action-bar"><button type="button" class="btn-primary add-row" data-template="message-template" data-target="message-cards" data-insert="prepend" data-focus="input[name=&quot;message_key[]&quot;]">' . h(t('New Template')) . '</button></div><div id="message-cards">';
    foreach ($messageRows as $row) {
        message_row((string)$row[0], (array)$row[1]);
    }
    echo'</div></div><div id="recipients-files" class="sub-view hidden" role="tabpanel"><div class="card"><div class="card-header"><h3>' . h(t('File Alias Registry')) . '</h3></div><div class="notice file-registry-note spaced-notice">' . h(t('Download directory:')) . ' <code>' . h($downloadBaseDir) . '</code><br>' . h(t('Place files there via SFTP, terminal, hosting file manager, or Docker volume. The UI lists safe files found there and lets you assign aliases.')) . '<br>' . h(t('Paths are shown for orientation only and are not edited in the Web UI.')) . '</div><div id="file-delete-bin"></div><div id="file-registry-body" class="file-registry-grid">';
    foreach ($fileRows as $row) {
        file_row((string)$row[0], (string)$row[1], (string)$row[2], (string)$row[3], (bool)$row[4], (bool)$row[5], (string)$row[6]);
    }
    if ($fileRows === []) {
        echo'<p class="helper-text empty-file-registry">' . h(t('No downloadable files were found. Add files to the download directory first; then return here to assign aliases.')) . '</p>';
    }
    echo'</div></div></div><div class="action-bar"><button type="button" class="btn-secondary reset-unsaved" data-reset-message="' . h(t('Unsaved changes will be discarded; last saved data will be reloaded.')) . '">' . h(t('Reset unsaved changes')) . '</button><button class="btn-primary" type="submit">' . h(t('Save')) . '</button></div></form>';
    templates($messageKeys, $fileAliases);
    echo'</section>';
}
